import{c as d,a as r,q as v,b as s,p as e,e as l,i}from"./index-CUwneGr6.js";const h={class:"sub-page"},o={class:"sub-nav-tabs"},n={key:0},u={key:1},p={key:2},q={__name:"RainbowCrystal",setup(m){const c=l("overview");return(f,a)=>(i(),d("div",h,[a[6]||(a[6]=r("div",{class:"page-header"},[r("h2",{class:"sub-page-title"},"彩虹水晶"),r("p",{class:"sub-page-desc"},"《光线传奇》第一部——七位守护者与彩虹水晶的奇幻冒险")],-1)),r("div",o,[r("button",{class:v(["sub-nav-tab",{active:c.value==="overview"}]),onClick:a[0]||(a[0]=t=>c.value="overview")},"故事概述",2),r("button",{class:v(["sub-nav-tab",{active:c.value==="episodes"}]),onClick:a[1]||(a[1]=t=>c.value="episodes")},"分集概述",2),r("button",{class:v(["sub-nav-tab",{active:c.value==="characters"}]),onClick:a[2]||(a[2]=t=>c.value="characters")},"人物志",2)]),c.value==="overview"?(i(),d("section",n,[...a[3]||(a[3]=[s('<div class="story-overview"><p><span class="highlight">《光线传奇》（Light Legend）</span>是由中国作家林倾雨创作的一部长篇奇幻科幻小说，系列主体包含三部正传及多部衍生作品。</p><p>小说的世界观建立在「地球」与「琳凯蒂亚」两个星球的宿命纠缠之上。地球一侧，是合肥老城鲜活具体的市井日常；琳凯蒂亚一侧，则是粉紫色天空下流淌着蜂蜜色溪流的梦幻异星。两个世界通过灵质、水晶与守护者的血脉紧密交织。</p><p>故事的核心冲突，既源于琳凯蒂亚因星陨之战造就的长达八百年的内部政变阴谋，也指向宇宙深处更大的未知威胁。小说探讨了一个核心命题：当一个人的身体、身份与命运被彻底击碎后，如何在日常的爱与羁绊中重新拼合自己。</p></div><div class="section-card"><h3>📖 第一部《彩虹水晶》故事简介</h3><div class="story-overview"><p>第一部《光线传奇之彩虹水晶》始于<span class="highlight">2015年8月25日</span>，合肥一中高二学生田野在小区楼下被两道来自外星的冰蓝与灰黑色光箭射中，体内潜藏的七颗彩虹水晶四散飞落，而他在琳凯蒂亚星球守护者「星使」的金光修复下，从一个18岁的少年变成约6岁的金发蓝眼女孩。</p><p>这场离奇的变故彻底颠覆了田野的人生，他被迫以全新的身份<span class="highlight">「妙可」</span>重新面对世界，一边适应这具陌生的身体，一边踏上寻找散落水晶、唤醒同伴、对抗外星叛逆者的征途。</p><p>第一部聚焦田野变身为妙可后的日常生活与重新成长，她从被家人接纳、被班主任薛老师以一道化学题认出、到中秋之夜在老家满月下获得短暂喘息。在这场跨越日常与奇幻的冒险中，妙可与儿时伙伴丽丽重逢，两人结伴踏上了收集七颗彩虹水晶、寻找同伴并将他们一一唤醒的旅程。</p><p>第一部《彩虹水晶》致敬了《哈利·波特》和《魔卡少女樱》，是关于勇气、友谊与文化交融的奇幻冒险。它既有寻找神器的经典叙事，也有对身份认同、家庭羁绊与成长代价的细腻书写。</p></div></div>',2)])])):e("",!0),c.value==="episodes"?(i(),d("section",u,[...a[4]||(a[4]=[s('<div class="section-card"><h3>📺 分集标题（共50集）</h3><div class="world-card"><h3>适应篇</h3><p><strong>第一集《彩虹落地的瞬间》</strong>——2015年8月25日下午，18岁少年田野被外星叛逆者的光箭射中，体内七颗彩虹水晶四散飞落，星使爷爷将其转化为约6岁的金发女孩。</p><p><strong>第二集《微光里的适应》</strong>——田野在变身第二天苏醒，确认自己已变成金发蓝眼的新疆面孔小女孩，在母亲用往事安抚下重获依靠感，深夜被金色星光托入高空，穿越纯白空间抵达梦幻异星琳凯蒂亚。</p><p><strong>第三集《当月空的星河闪耀时》</strong>——田野变身第三天，在父母陪同下登门拜访班主任薛老师，以化学题证明自己身份。田父以「妙可」之名——源自milky way的谐音——为她正式赐予新名字。</p></div><div class="world-card"><h3>人物拓展篇</h3><p><strong>第四集《儿时伙伴的重逢》</strong>——变成六岁女孩的田妙可在星虹中学操场外偶遇童年挚友丽丽，丽丽在危急时刻觉醒星力。星帝星母在琳凯蒂亚水晶球中见证女儿归来。</p><p><strong>第五集《在暴风雨中的少女》</strong>——2015年9月，少女梦云因中考失利与家庭决裂，被外星叛逆者拉拢。妙可与丽丽展开寻找，但梦云已在韩斌精心设计的虚荣中越陷越深。</p><p><strong>第六集《故乡的明月》</strong>——在连绵阴雨二十五天后，妙可中秋与家人回到农村老家，在满月下获得短暂喘息。次日月全食时分，姐姐梦雪突然晕倒。</p></div><div class="world-card"><h3>后续篇章</h3><p>世界观第一次拓宽篇（第七~十一集）、情感篇（第十二~十六集）、灾难篇（第十七~十九集）、儿时篇（第二十~二十四集）、微世界+星空篇（第二十五~二十六集）、古代篇（第二十七~三十一集）……共50集。</p></div></div>',1)])])):e("",!0),c.value==="characters"?(i(),d("section",p,[...a[5]||(a[5]=[s('<div class="section-card"><h3>👤 七位彩虹水晶守护者（第6代）</h3><div class="character-grid"><div class="character-card"><div class="character-header"><div class="character-avatar hero">☀️</div><div><div class="character-name">田妙可（索菲·琳）</div><div class="character-role">太阳使者 · 红色水晶守护者</div></div></div><div class="character-info">预言中打破循环的核心人物，琳凯蒂亚公主。2015年8月25日正式觉醒。灵魂18岁，身体6岁，深金色卷曲长发，蓝色眼睛，额间有太阳印记。</div></div><div class="character-card"><div class="character-header"><div class="character-avatar hero">⚡</div><div><div class="character-name">俊哥（雷恩·斯塔尔）</div><div class="character-role">电磁使者 · 绿色水晶守护者</div></div></div><div class="character-info">最早抵达地球的守护者，1990年转世，2008年首次觉醒。25岁，电力工程师，踏实靠谱，默默付出。梦雪的丈夫。</div></div><div class="character-card"><div class="character-header"><div class="character-avatar hero">🌙</div><div><div class="character-name">田梦雪（露娜·琳）</div><div class="character-role">金月使者 · 黄色水晶守护者</div></div></div><div class="character-info">22岁，开朗体贴，田妙可的姐姐。2009年日全食觉醒被困，2015年中秋意识链接，唯一经历过长时间半觉醒状态的成员。</div></div><div class="character-card"><div class="character-header"><div class="character-avatar hero">⭐</div><div><div class="character-name">丽丽（黛拉·琳）</div><div class="character-role">星辰使者 · 紫色水晶守护者</div></div></div><div class="character-info">15岁，星虹中学高一新生，妙可的童年挚友。2015年9月2日正式觉醒，觉醒后前往中国北方，是守护者阵营的核心成员。</div></div><div class="character-card"><div class="character-header"><div class="character-avatar villain">💧</div><div><div class="character-name">韩斌（古劳奇·雷）</div><div class="character-role">云雨使者 · 青色水晶守护者</div></div></div><div class="character-info">17岁，合肥一中高二学生。2015年8月被外星叛逆者「古劳奇」附身，走向与守护者对立，是「走错路的自己人」。</div></div><div class="character-card"><div class="character-header"><div class="character-avatar villain">⏳</div><div><div class="character-name">俊伟（泰倍斯·锡）</div><div class="character-role">时空使者 · 蓝色水晶守护者</div></div></div><div class="character-info">18岁，无业游民。2015年8月被外星叛逆者「时空」附身，阴鸷冷酷，心机深沉，计划坐收渔翁之利抢夺七颗彩虹水晶。</div></div><div class="character-card"><div class="character-header"><div class="character-avatar hero">🌪️</div><div><div class="character-name">笑林（科摩林·锡）</div><div class="character-role">风尘使者 · 橙色水晶守护者</div></div></div><div class="character-info">2016年正式登场，最后一位觉醒的守护者，补齐了七位守护者的完整阵营。</div></div></div></div><div class="section-card"><h3>👤 主要配角</h3><div class="character-grid"><div class="character-card"><div class="character-header"><div class="character-avatar neutral">👴</div><div><div class="character-name">星使爷爷</div><div class="character-role">琳凯蒂亚星球守护者</div></div></div><div class="character-info">须发皆白、身披流光银袍、手持木质法杖。在田野被光箭射中后及时出现，用金光修复其身体并转化为6岁女孩，是妙可的使命引导者。</div></div><div class="character-card"><div class="character-header"><div class="character-avatar neutral">❤️</div><div><div class="character-name">白雪</div><div class="character-role">田野女友</div></div></div><div class="character-info">17岁，合肥一中高二学生，相貌可爱，温柔敏感，体内含红色水晶。擅长整理复习资料，对妙可的异常隐隐察觉却不敢相信。</div></div><div class="character-card"><div class="character-header"><div class="character-avatar neutral">👨‍🏫</div><div><div class="character-name">薛老师</div><div class="character-role">班主任</div></div></div><div class="character-info">45岁，教龄22年，正直护短，理性务实。是第一个接纳田野变身真相的外人，承诺单独送卷、辅导学业，全力守护妙可的高考之路。</div></div><div class="character-card"><div class="character-header"><div class="character-avatar neutral">👨</div><div><div class="character-name">昊天</div><div class="character-role">田野最好的兄弟</div></div></div><div class="character-info">18岁，大大咧咧，重情重义，球技好。和妙可约定一起考上南京大学，球场铁三角之一。</div></div></div></div><div class="section-card"><h3>👨‍👩‍👧 田家亲属</h3><div class="character-grid"><div class="character-card"><div class="character-header"><div class="character-avatar neutral">👨‍🌾</div><div><div class="character-name">田父</div><div class="character-role">农民 / 建筑工程师</div></div></div><div class="character-info">53岁，沉稳内敛、不善言辞但父爱深沉。出身合肥乡村，靠双手撑起家庭。1997年在老家门槛上为儿子取名&quot;田野&quot;，2015年以童年英语回忆为灵感，为变身的女儿取名&quot;妙可&quot;（取自milky way银河的谐音）。</div></div><div class="character-card"><div class="character-header"><div class="character-avatar neutral">👩‍👦</div><div><div class="character-name">田母</div><div class="character-role">全职家庭主妇</div></div></div><div class="character-info">48岁，温柔坚韧、细心周到、共情力强。出身大兴安岭城镇，后嫁到合肥。是第一个目睹田野出生时光蝴蝶异象的人，全程陪伴田野变身前后的所有艰难时刻，是孩子最坚实的情绪后盾。</div></div><div class="character-card"><div class="character-header"><div class="character-avatar neutral">👶</div><div><div class="character-name">昊辰</div><div class="character-role">梦雪与俊哥之子</div></div></div><div class="character-info">2岁，天真懵懂、嗅觉敏锐。梦雪和俊哥的儿子，嗅觉异常敏锐，只认&quot;香香姐姐&quot;，是第一个毫无芥蒂接纳变身的妙可的人。</div></div></div></div><div class="section-card"><h3>🏪 七姑一家</h3><div class="character-grid"><div class="character-card"><div class="character-header"><div class="character-avatar neutral">🔪</div><div><div class="character-name">七姑</div><div class="character-role">社区生鲜店店主</div></div></div><div class="character-info">40岁，大嗓门热心肠，急躁心软，行动力爆表。田父的妹妹，在新城小区一楼经营生鲜店。是第一个发现田野变身的亲属，变身事件后主动组织家庭聚会，给妙可买衣服和食物，是田家的&quot;后勤部长&quot;。</div></div><div class="character-card"><div class="character-header"><div class="character-avatar neutral">👓</div><div><div class="character-name">姑爷</div><div class="character-role">社区生鲜店店主</div></div></div><div class="character-info">40岁，沉稳寡言，细心靠谱，按章办事，喜欢拿小本本记录一切。七姑的丈夫，戴单把眼镜，变身事件后默默帮忙处理杂事，是七姑的得力助手。</div></div><div class="character-card"><div class="character-header"><div class="character-avatar neutral">👧</div><div><div class="character-name">梦云</div><div class="character-role">七姑长女</div></div></div><div class="character-info">16岁，内向少言。七姑的大女儿，变身事件后嘴上说不想来但全程牵挂。第五集因中考失利与家庭决裂，被外星叛逆者拉拢，在韩斌精心设计的虚荣中越陷越深。</div></div><div class="character-card"><div class="character-header"><div class="character-avatar neutral">🎀</div><div><div class="character-name">二瑞</div><div class="character-role">小学四年级学生</div></div></div><div class="character-info">10岁，活泼贴心，心眼强会说话，极度崇拜田野。七姑的二女儿，变身事件后主动送裙子和画画，是妙可的小迷妹。</div></div><div class="character-card"><div class="character-header"><div class="character-avatar neutral">⚽</div><div><div class="character-name">三宝</div><div class="character-role">小学二年级学生</div></div></div><div class="character-info">8岁，好动天真，有点调皮但懂事，认人不认脸。七姑的小儿子，从喊&quot;田野哥哥&quot;无缝切换到&quot;姐姐&quot;，经常拉着妙可玩。</div></div></div></div><div class="section-card"><h3>👑 琳凯蒂亚皇族</h3><div class="character-grid"><div class="character-card"><div class="character-header"><div class="character-avatar neutral">✨</div><div><div class="character-name">琳凯蒂亚星后</div><div class="character-role">世宏天母</div></div></div><div class="character-info">身着白色长裙，浑身散发圣洁光芒。温柔圣洁，充满母爱。田妙可的异星生母，仅在光镜中出现，告知妙可&quot;水晶守护者&quot;的使命，以及她还有一位名叫丽丽的伙伴。</div></div><div class="character-card"><div class="character-header"><div class="character-avatar neutral">👑</div><div><div class="character-name">琳凯蒂亚星帝</div><div class="character-role">召归大帝</div></div></div><div class="character-info">琳凯蒂亚星球的统治者，田妙可的异星生父。星帝星母在琳凯蒂亚水晶球中见证女儿归来，守护着琳凯蒂亚星球的命运。</div></div></div></div><div class="section-card"><h3>🎓 同窗好友</h3><div class="character-grid"><div class="character-card"><div class="character-header"><div class="character-avatar neutral">🏀</div><div><div class="character-name">李哲</div><div class="character-role">合肥一中高二学生</div></div></div><div class="character-info">18岁，性格内敛，球技精湛，观察力强。田野的同班同学，球场铁三角之一，第一个说出&quot;她真的太像田野了&quot;的人。</div></div><div class="character-card"><div class="character-header"><div class="character-avatar neutral">🎒</div><div><div class="character-name">郭清逸</div><div class="character-role">合肥一中高二学生</div></div></div><div class="character-info">田野的兄弟，球场伙伴，与昊天、李哲共同组成田野的好友圈，见证了田野变身前后的种种变化。</div></div><div class="character-card"><div class="character-header"><div class="character-avatar neutral">📚</div><div><div class="character-name">袁玮</div><div class="character-role">合肥一中高二学生</div></div></div><div class="character-info">田野的兄弟之一，与昊天、李哲、郭清逸共同构成田野在合肥一中的核心社交圈。</div></div></div></div><div class="section-card"><h3>🏘️ 邻里与配角</h3><div class="character-grid"><div class="character-card"><div class="character-header"><div class="character-avatar neutral">🍦</div><div><div class="character-name">张奶奶</div><div class="character-role">小区冰棍摊主</div></div></div><div class="character-info">60余岁，朴实憨厚，易吃惊。新城小区卖冰棍的老人，是第一个目睹田野变身的邻居，惊呼&quot;仙女下凡&quot;。</div></div><div class="character-card"><div class="character-header"><div class="character-avatar neutral">👷</div><div><div class="character-name">张哥</div><div class="character-role">田父同事</div></div></div><div class="character-info">51岁，热情爽朗，嗓门洪亮。田父的同事，正在给大儿子筹备婚房。偶遇变身后的妙可，误以为是田家远房混血亲戚。</div></div><div class="character-card"><div class="character-header"><div class="character-avatar neutral">🤱</div><div><div class="character-name">张嫂</div><div class="character-role">张哥妻子</div></div></div><div class="character-info">49岁，热心肠，爱孩子。张哥的妻子，见了可爱的小姑娘就挪不开眼。</div></div><div class="character-card"><div class="character-header"><div class="character-avatar neutral">🔬</div><div><div class="character-name">物理老师</div><div class="character-role">合肥一中物理教师</div></div></div><div class="character-info">40余岁，认真负责，略带古板。第一集出场，韩斌被附身时正在讲凸透镜成像原理。</div></div><div class="character-card"><div class="character-header"><div class="character-avatar neutral">🤰</div><div><div class="character-name">接生婆</div><div class="character-role">乡村接生婆</div></div></div><div class="character-info">50余岁，经验丰富，嗓门洪亮。1997年在合肥乡村为田母接生，第一个发现田野额间的太阳胎记，预言&quot;将来指定不是个凡人&quot;。</div></div><div class="character-card"><div class="character-header"><div class="character-avatar neutral">🏠</div><div><div class="character-name">胖婶、瘦叔</div><div class="character-role">小区居民</div></div></div><div class="character-info">40余岁，热心好奇。新城小区邻居，见证了田野变身的全过程。</div></div></div></div>',7)])])):e("",!0)]))}};export{q as default};
